import React, { useRef, useEffect, useState } from 'react';
import { usePlayer } from '../context/PlayerContext';
import { FaPlay, FaPause, FaStepForward, FaStepBackward, FaRandom, FaRedo, FaVolumeUp, FaHeart, FaUserPlus, FaList } from 'react-icons/fa';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';
import { Link } from 'react-router-dom'; // Import Link

const Player = () => {
  const { currentSong, isPlaying, setIsPlaying, togglePlay } = usePlayer();
  const { user, updateUser } = useAuth(); // Lấy thông tin user
  const audioRef = useRef(null);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);

  // Xử lý Play/Pause khi đổi bài
  useEffect(() => {
    if (currentSong && audioRef.current) {
      if (isPlaying) {
        audioRef.current.play();
      } else {
        audioRef.current.pause();
      }
    }
  }, [currentSong, isPlaying]);

  // Cập nhật thời gian thực
  const handleTimeUpdate = () => {
    if(audioRef.current) {
        setCurrentTime(audioRef.current.currentTime);
        setDuration(audioRef.current.duration || 0);
    }
  };

  // Tua nhạc
  const handleSeek = (e) => {
    const seekTime = (e.target.value / 100) * duration;
    audioRef.current.currentTime = seekTime;
    setCurrentTime(seekTime);
  };

  // Format giây thành phút:giây (ví dụ: 3:57)
  const formatTime = (time) => {
    if (!time) return "0:00";
    const min = Math.floor(time / 60);
    const sec = Math.floor(time % 60);
    return `${min}:${sec < 10 ? '0' + sec : sec}`;
  };

  // Hàm xử lý Like ngay trên Player
  const handleLike = async () => {
      if (!user) return alert("Please login to like songs!");
      if (!currentSong) return;

      try {
          const res = await axios.put(`http://localhost:5000/api/users/like/${currentSong._id}`, {}, {
             headers: { token: `Bearer ${user.token}` }
          });
          
          // Cập nhật user context để tim chuyển đỏ/trắng ngay lập tức
          if (res.data === "Liked") {
              updateUser({ likedSongs: [...(user.likedSongs || []), currentSong._id] });
          } else {
              updateUser({ likedSongs: (user.likedSongs || []).filter(songId => songId !== currentSong._id) });
          }
      } catch (err) {
          console.error(err);
      }
  };

  if (!currentSong) return null;

  // Kiểm tra trạng thái Like của bài đang phát
  const isLiked = user?.likedSongs?.includes(currentSong._id);

  return (
    <div className="fixed bottom-0 left-0 right-0 bg-[#111] text-white h-[60px] border-t border-[#333] flex items-center px-2 md:px-4 z-50 font-sans select-none justify-between">
      {/* Audio Element Ẩn */}
      <audio 
        ref={audioRef} 
        src={currentSong.audioUrl} 
        onEnded={() => setIsPlaying(false)}
        onTimeUpdate={handleTimeUpdate}
        onLoadedMetadata={handleTimeUpdate}
      />

      {/* 1. Nhóm Điều Khiển (Trái) */}
      {/* Mobile: Chỉ hiện Play/Next. Desktop: Hiện đủ */}
      <div className="flex items-center gap-4 md:gap-6 w-auto md:w-[240px] justify-start flex-shrink-0">
        <button className="text-white hover:text-orange-500 transition hidden md:block"><FaStepBackward size={18} /></button>
        <button 
          onClick={togglePlay}
          className="text-white hover:text-orange-500 transition"
        >
          {isPlaying ? <FaPause size={24} className="md:w-7 md:h-7" /> : <FaPlay size={24} className="md:w-7 md:h-7" />}
        </button>
        <button className="text-white hover:text-orange-500 transition"><FaStepForward size={18} /></button>
        <button className="text-gray-400 hover:text-white hidden lg:block"><FaRandom size={16} /></button>
        <button className="text-gray-400 hover:text-white hidden lg:block"><FaRedo size={16} /></button>
      </div>

      {/* 2. Thanh Tiến Trình (Giữa) - Ẩn trên Mobile, Hiện trên Desktop */}
      <div className="flex-1 flex items-center gap-4 px-4 hidden md:flex">
        <span className="text-[#f50] text-xs font-medium w-10 text-right">{formatTime(currentTime)}</span>
        
        <div className="relative flex-1 h-[2px] bg-[#333] group cursor-pointer">
           <input 
              type="range" 
              min="0" 
              max="100" 
              value={duration ? (currentTime / duration) * 100 : 0}
              onChange={handleSeek}
              className="absolute w-full h-[12px] -top-[5px] opacity-0 cursor-pointer z-20"
           />
           <div className="absolute top-0 left-0 w-full h-full bg-[#333]"></div>
           <div 
              className="absolute top-0 left-0 h-full bg-[#f50]" 
              style={{ width: `${duration ? (currentTime / duration) * 100 : 0}%` }}
           ></div>
           <div 
              className="absolute top-1/2 -translate-y-1/2 w-3 h-3 bg-[#f50] rounded-full opacity-0 group-hover:opacity-100 transition z-10 pointer-events-none"
              style={{ left: `${duration ? (currentTime / duration) * 100 : 0}%` }}
           ></div>
        </div>

        <span className="text-gray-400 text-xs font-medium w-10">{formatTime(duration)}</span>
        <button className="text-white hover:text-white ml-2"><FaVolumeUp size={18} /></button>
      </div>

      {/* 3. Thông Tin Bài Hát (Phải) */}
      <div className="flex items-center gap-2 md:gap-4 px-2 md:px-6 w-auto md:w-[360px] justify-end border-l-0 md:border-l border-[#333] h-full flex-shrink min-w-0">
        <div className="flex items-center gap-3 flex-1 min-w-0">
            {/* Bọc ảnh bìa bằng Link */}
            <Link to={`/song/${currentSong._id}`}>
                <img src={currentSong.coverImage || 'https://via.placeholder.com/40'} alt="cover" className="w-10 h-10 object-cover shadow-sm rounded md:rounded-none hover:opacity-80 transition" />
            </Link>
            
            <div className="flex flex-col justify-center overflow-hidden">
                <span className="text-gray-400 text-[10px] md:text-[11px] truncate hover:underline cursor-pointer">{currentSong.artist}</span>
                {/* Bọc tên bài hát bằng Link */}
                <Link to={`/song/${currentSong._id}`} className="text-gray-200 text-xs truncate font-medium hover:text-white cursor-pointer hover:underline">
                    {currentSong.title}
                </Link>
            </div>
        </div>

        <div className="flex items-center gap-3 md:gap-5 text-white">
            {/* Nút Like đã được cập nhật logic */}
            <button 
                onClick={handleLike}
                className={`transition ${isLiked ? 'text-red-500' : 'hover:text-orange-500'}`}
                title={isLiked ? "Unlike" : "Like"}
            >
                <FaHeart size={16} />
            </button>
            
            <button className="hover:text-orange-500 transition hidden sm:block"><FaUserPlus size={18} /></button>
            <button className="hover:text-orange-500 transition hidden sm:block"><FaList size={18} /></button>
        </div>
      </div>

      {/* Mobile Progress Bar (Thanh chạy nhỏ xíu trên cùng player cho Mobile) */}
      <div className="absolute top-0 left-0 right-0 h-[2px] bg-[#333] md:hidden pointer-events-none">
        <div 
            className="h-full bg-[#f50]" 
            style={{ width: `${duration ? (currentTime / duration) * 100 : 0}%` }}
        ></div>
      </div>
    </div>
  );
};

export default Player;
